PythonGo <pre><code>from kreuzberg import register_document_extractor, ExtractionResult
import json

class CustomJsonExtractor:
    def name(self) -&gt; str:
        return "custom-json-extractor"

    def version(self) -&gt; str:
        return "1.0.0"

    def supported_mime_types(self) -&gt; list[str]:
        return ["application/json", "text/json"]

    def priority(self) -&gt; int:
        return 50

    def extract_bytes(
        self,
        content: bytes,
        mime_type: str,
        config: dict
    ) -&gt; ExtractionResult:
        data = json.loads(content)
        text = self._extract_text(data)

        return {
            "content": text,
            "mime_type": "application/json",
            "metadata": {},
            "tables": [],
        }

    def _extract_text(self, obj) -&gt; str:
        if isinstance(obj, str):
            return f"{obj}\\n"
        elif isinstance(obj, list):
            return "".join(self._extract_text(item) for item in obj)
        elif isinstance(obj, dict):
            return "".join(self._extract_text(v) for v in obj.values())
        return ""

    def initialize(self) -&gt; None:
        pass

    def shutdown(self) -&gt; None:
        pass

# Register the extractor
register_document_extractor(CustomJsonExtractor())
