func main() {
    maxChars := 1000
    maxOverlap := 200
    config := &amp;kreuzberg.ExtractionConfig{
        Chunking: &amp;kreuzberg.ChunkingConfig{
            MaxChars:   &amp;maxChars,
            MaxOverlap: &amp;maxOverlap,
        },
